    "code": "package main\ntype SparseVector struct {\n\tpairs [][2]int\n}\n\nfunc Constructor(nums []int) SparseVector {\n\tvar pairs [][2]int\n\tfor i, v := range nums {\n\t\tif v != 0 {\n\t\t\tpairs = append(pairs, [2]int{i, v})\n\t\t}\n\t}\n\treturn SparseVector{pairs}\n}\n\nfunc (sv *SparseVector) DotProduct(vec SparseVector) int {\n\tres, i, j := 0, 0, 0\n\tfor i < len(sv.pairs) && j < len(vec.pairs) {\n\t\tif sv.pairs[i][0] == vec.pairs[j][0] {\n\t\t\tres += sv.pairs[i][1] * vec.pairs[j][1]\n\t\t\ti++\n\t\t\tj++\n\t\t} else if sv.pairs[i][0] < vec.pairs[j][0] {\n\t\t\ti++\n\t\t} else {\n\t\t\tj++\n\t\t}\n\t}\n\treturn res\n}\n",
