    "scene": "Tiny URLs carved on tombstones — encode long screams into short hex; decode before the grave collapses — Design An Expression Tree With Evaluate Function.",
    "acquired": "Postfix corpse stack: pop two limbs, weld operator spine, push node—leaves scream numbers, roots crunch math",
    "time": "O(n)",
    "space": "O(n)",
    "code": "package main\nimport \"strconv\"\n\n\ntype ExprNode struct {\n\tval         string\n\tleft, right *ExprNode\n}\n\nfunc (n *ExprNode) Evaluate() int {\n\tif n.left == nil {\n\t\tv, _ := strconv.Atoi(n.val)\n\t\treturn v\n\t}\n\tl, r := n.left.Evaluate(), n.right.Evaluate()\n\tswitch n.val {\n\tcase \"+\":\n\t\treturn l + r\n\tcase \"-\":\n\t\treturn l - r\n\tcase \"*\":\n\t\treturn l * r\n\tcase \"/\":\n\t\treturn l / r\n\t}\n\treturn 0\n}\n\nfunc buildTree(postfix []string) *ExprNode {\n\tvar stack []*ExprNode\n\tfor _, tok := range postfix {\n\t\tif tok == \"+\" || tok == \"-\" || tok == \"*\" || tok == \"/\" {\n\t\t\tr, l := stack[len(stack)-1], stack[len(stack)-2]\n\t\t\tstack = stack[:len(stack)-2]\n\t\t\tstack = append(stack, &ExprNode{tok, l, r})\n\t\t} else {\n\t\t\tstack = append(stack, &ExprNode{val: tok})\n\t\t}\n\t}\n\treturn stack[0]\n}\n\ntype TreeBuilder struct{}\n\nfunc (tb *TreeBuilder) BuildTree(postfix []string) *ExprNode {\n\treturn buildTree(postfix)\n}\n",
