    "code": "package main\nfunc tinyUrlEncodeID(id int) string {\n\tconst digits = \"0123456789abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ\"\n\tif id == 0 {\n\t\treturn string(digits[0])\n\t}\n\tvar out []byte\n\tfor id > 0 {\n\t\tout = append(out, digits[id%62])\n\t\tid /= 62\n\t}\n\tfor l, r := 0, len(out)-1; l < r; l, r = l+1, r-1 {\n\t\tout[l], out[r] = out[r], out[l]\n\t}\n\treturn string(out)\n}\n\ntype tinyUrl struct {\n\tnextID  int\n\ttoShort map[string]string\n\ttoLong  map[string]string\n\tbase    string\n}\n\nfunc newTinyUrl(host string) *tinyUrl {\n\treturn &tinyUrl{\n\t\ttoShort: map[string]string{},\n\t\ttoLong:  map[string]string{},\n\t\tbase:    host,\n\t}\n}\n\nfunc (t *tinyUrl) encode(longURL string) string {\n\tif short, ok := t.toLong[longURL]; ok {\n\t\treturn short\n\t}\n\tt.nextID++\n\tshort := t.base + \"/\" + tinyUrlEncodeID(t.nextID)\n\tt.toShort[short] = longURL\n\tt.toLong[longURL] = short\n\treturn short\n}\n\nfunc (t *tinyUrl) decode(shortURL string) (string, bool) {\n\tlongURL, ok := t.toShort[shortURL]\n\treturn longURL, ok\n}\n",
