    "pattern": "Sort by end + DP + binary search",
    "visual": "Sort by end; dp = max(skip, take + best earlier non-overlapping job)",
    "memorize": "sort by end; dp[i]=max(dp[i-1], profit+dp[lastNonOverlap])",
    "scene": "A depth-first spelunker paints visited caves; backtrack when dead ends hiss — sort by end; dp[i]=max(dp[i-1], profit+dp[lastNonOverlap]).",
    "acquired": "sort by end; dp[i]=max(dp[i-1], profit+dp[lastNonOverlap])",
    "time": "O(n log n)",
    "space": "O(n)",
    "code": "package main\nimport (\n\t\"sort\"\n)\n\n\ntype Job struct {\n\tStart  int\n\tEnd    int\n\tProfit int\n}\n\nfunc lastNotOverlapJob(jobs []Job, idx int) int {\n\tlo, hi := 0, idx-1\n\tres := -1\n\tfor lo <= hi {\n\t\tmid := lo + (hi-lo)/2\n\t\tif jobs[mid].End <= jobs[idx].Start {\n\t\t\tres = mid\n\t\t\tlo = mid + 1\n\t\t} else {\n\t\t\thi = mid - 1\n\t\t}\n\t}\n\treturn res\n}\n\nfunc maxProfit(jobs []Job) int {\n\tif len(jobs) == 0 {\n\t\treturn 0\n\t}\n\tsorted := make([]Job, len(jobs))\n\tcopy(sorted, jobs)\n\tsort.Slice(sorted, func(i, j int) bool {\n\t\treturn sorted[i].End < sorted[j].End\n\t})\n\tn := len(sorted)\n\tdp := make([]int, n)\n\tdp[0] = sorted[0].Profit\n\tfor i := 1; i < n; i++ {\n\t\tprofit := sorted[i].Profit\n\t\tprev := lastNotOverlapJob(sorted, i)\n\t\tif prev != -1 {\n\t\t\tprofit += dp[prev]\n\t\t}\n\t\tif dp[i-1] > profit {\n\t\t\tdp[i] = dp[i-1]\n\t\t} else {\n\t\t\tdp[i] = profit\n\t\t}\n\t}\n\treturn dp[n-1]\n}\n",
