    "code": "package main\ntype MultilevelNode struct {\n\tVal        int\n\tPrev, Next *MultilevelNode\n\tChild      *MultilevelNode\n}\n\nfunc flattenDoublyLinkedList(head *MultilevelNode) *MultilevelNode {\n\tif head == nil {\n\t\treturn nil\n\t}\n\tvar prev *MultilevelNode\n\tvar dfs func(node *MultilevelNode) *MultilevelNode\n\tdfs = func(node *MultilevelNode) *MultilevelNode {\n\t\tif node == nil {\n\t\t\treturn nil\n\t\t}\n\t\tif prev != nil {\n\t\t\tprev.Next = node\n\t\t\tnode.Prev = prev\n\t\t}\n\t\tprev = node\n\t\tnext := node.Next\n\t\tif node.Child != nil {\n\t\t\ttail := dfs(node.Child)\n\t\t\tnode.Next = node.Child\n\t\t\tnode.Child.Prev = node\n\t\t\tnode.Child = nil\n\t\t\tif next != nil {\n\t\t\t\ttail.Next = next\n\t\t\t\tnext.Prev = tail\n\t\t\t}\n\t\t\tprev = tail\n\t\t}\n\t\tif next != nil {\n\t\t\treturn dfs(next)\n\t\t}\n\t\treturn node\n\t}\n\tdfs(head)\n\treturn head\n}\n",
