    "code": "package main\ntype Node struct {\n\tVal  int\n\tNext *Node\n}\n\nfunc insert(head *Node, insertVal int) *Node {\n\tnode := &Node{Val: insertVal}\n\tif head == nil {\n\t\tnode.Next = node\n\t\treturn node\n\t}\n\tprev, cur := head, head.Next\n\tfor {\n\t\tif prev.Val <= insertVal && insertVal <= cur.Val {\n\t\t\tbreak\n\t\t}\n\t\tif prev.Val > cur.Val {\n\t\t\tif insertVal >= prev.Val || insertVal <= cur.Val {\n\t\t\t\tbreak\n\t\t\t}\n\t\t}\n\t\tprev, cur = cur, cur.Next\n\t\tif prev == head {\n\t\t\tbreak\n\t\t}\n\t}\n\tprev.Next = node\n\tnode.Next = cur\n\treturn head\n}\n",
