    "code": "package main\nimport \"strings\"\n\n\nfunc numberToWords(num int) string {\n\tif num == 0 {\n\t\treturn \"Zero\"\n\t}\n\tbelow20 := []string{\"\", \"One\", \"Two\", \"Three\", \"Four\", \"Five\", \"Six\", \"Seven\", \"Eight\", \"Nine\", \"Ten\", \"Eleven\", \"Twelve\", \"Thirteen\", \"Fourteen\", \"Fifteen\", \"Sixteen\", \"Seventeen\", \"Eighteen\", \"Nineteen\"}\n\ttens := []string{\"\", \"\", \"Twenty\", \"Thirty\", \"Forty\", \"Fifty\", \"Sixty\", \"Seventy\", \"Eighty\", \"Ninety\"}\n\tthousands := []string{\"\", \"Thousand\", \"Million\", \"Billion\"}\n\tvar helper func(n int) string\n\thelper = func(n int) string {\n\t\tif n == 0 {\n\t\t\treturn \"\"\n\t\t}\n\t\tif n < 20 {\n\t\t\treturn below20[n]\n\t\t}\n\t\tif n < 100 {\n\t\t\tr := tens[n/10]\n\t\t\tif n%10 > 0 {\n\t\t\t\tr += \" \" + below20[n%10]\n\t\t\t}\n\t\t\treturn r\n\t\t}\n\t\tr := below20[n/100] + \" Hundred\"\n\t\tif n%100 > 0 {\n\t\t\tr += \" \" + helper(n%100)\n\t\t}\n\t\treturn r\n\t}\n\tvar parts []string\n\tidx := 0\n\tfor num > 0 {\n\t\tif num%1000 != 0 {\n\t\t\ts := helper(num % 1000)\n\t\t\tif thousands[idx] != \"\" {\n\t\t\t\ts += \" \" + thousands[idx]\n\t\t\t}\n\t\t\tparts = append([]string{s}, parts...)\n\t\t}\n\t\tnum /= 1000\n\t\tidx++\n\t}\n\treturn strings.Join(parts, \" \")\n}\n",
