    "code": "package main\nfunc minOperations(nums1 []int, nums2 []int) int {\n\tif len(nums1) > len(nums2)*6 || len(nums2) > len(nums1)*6 {\n\t\treturn -1\n\t}\n\tsum1, sum2 := 0, 0\n\tfor _, x := range nums1 {\n\t\tsum1 += x\n\t}\n\tfor _, x := range nums2 {\n\t\tsum2 += x\n\t}\n\tif sum1 > sum2 {\n\t\tnums1, nums2 = nums2, nums1\n\t\tsum1, sum2 = sum2, sum1\n\t}\n\tdiff := sum2 - sum1\n\tif diff == 0 {\n\t\treturn 0\n\t}\n\tvar contrib [6]int\n\tfor _, x := range nums1 {\n\t\tcontrib[6-x]++\n\t}\n\tfor _, x := range nums2 {\n\t\tcontrib[x-1]++\n\t}\n\tops := 0\n\tfor c := 5; c >= 1 && diff > 0; c-- {\n\t\ttake := contrib[c]\n\t\tneed := (diff + c - 1) / c\n\t\tif take > need {\n\t\t\ttake = need\n\t\t}\n\t\tops += take\n\t\tdiff -= take * c\n\t}\n\tif diff > 0 {\n\t\treturn -1\n\t}\n\treturn ops\n}\n",
