    "code": "package main\ntype streamItem struct {\n\tval    int\n\tstream int\n\tidx    int\n}\n\ntype mergeHeap struct {\n\titems []streamItem\n}\n\nfunc (h *mergeHeap) push(it streamItem) {\n\th.items = append(h.items, it)\n\ti := len(h.items) - 1\n\tfor i > 0 {\n\t\tp := (i - 1) / 2\n\t\tif h.items[p].val <= h.items[i].val {\n\t\t\tbreak\n\t\t}\n\t\th.items[p], h.items[i] = h.items[i], h.items[p]\n\t\ti = p\n\t}\n}\n\nfunc (h *mergeHeap) popMin() streamItem {\n\ttop := h.items[0]\n\tlast := h.items[len(h.items)-1]\n\th.items = h.items[:len(h.items)-1]\n\tif len(h.items) == 0 {\n\t\treturn top\n\t}\n\th.items[0] = last\n\ti := 0\n\tfor {\n\t\tl, r := 2*i+1, 2*i+2\n\t\tsmallest := i\n\t\tif l < len(h.items) && h.items[l].val < h.items[smallest].val {\n\t\t\tsmallest = l\n\t\t}\n\t\tif r < len(h.items) && h.items[r].val < h.items[smallest].val {\n\t\t\tsmallest = r\n\t\t}\n\t\tif smallest == i {\n\t\t\tbreak\n\t\t}\n\t\th.items[i], h.items[smallest] = h.items[smallest], h.items[i]\n\t\ti = smallest\n\t}\n\treturn top\n}\n\nfunc mergeKSortedStreamsInOne(streams [][]int) []int {\n\th := &mergeHeap{}\n\tfor si, s := range streams {\n\t\tif len(s) > 0 {\n\t\t\th.push(streamItem{val: s[0], stream: si, idx: 0})\n\t\t}\n\t}\n\tvar out []int\n\tfor len(h.items) > 0 {\n\t\tit := h.popMin()\n\t\tout = append(out, it.val)\n\t\tnext := it.idx + 1\n\t\tif next < len(streams[it.stream]) {\n\t\t\th.push(streamItem{val: streams[it.stream][next], stream: it.stream, idx: next})\n\t\t}\n\t}\n\treturn out\n}\n",
