    "code": "package main\nfunc minWindowSubstring(s, t string) string {\n\tif len(t) == 0 {\n\t\treturn \"\"\n\t}\n\tneed := map[byte]int{}\n\tfor i := 0; i < len(t); i++ {\n\t\tneed[t[i]]++\n\t}\n\trequired := len(need)\n\tformed := 0\n\thave := map[byte]int{}\n\tl, bestL, bestLen := 0, 0, int(^uint(0)>>1)\n\tfor r := 0; r < len(s); r++ {\n\t\tc := s[r]\n\t\thave[c]++\n\t\tif cnt, ok := need[c]; ok && have[c] == cnt {\n\t\t\tformed++\n\t\t}\n\t\tfor formed == required && l <= r {\n\t\t\tif r-l+1 < bestLen {\n\t\t\t\tbestLen = r - l + 1\n\t\t\t\tbestL = l\n\t\t\t}\n\t\t\tleft := s[l]\n\t\t\thave[left]--\n\t\t\tif cnt, ok := need[left]; ok && have[left] < cnt {\n\t\t\t\tformed--\n\t\t\t}\n\t\t\tl++\n\t\t}\n\t}\n\tif bestLen == int(^uint(0)>>1) {\n\t\treturn \"\"\n\t}\n\treturn s[bestL : bestL+bestLen]\n}\n",
