    "time": "O(n^2)",
    "space": "O(n)",
    "code": "package main\nfunc wordWrap(words []string, maxWidth int) []string {\n\tn := len(words)\n\tif n == 0 {\n\t\treturn nil\n\t}\n\tdp := make([]int, n+1)\n\tnext := make([]int, n)\n\tfor i := n - 1; i >= 0; i-- {\n\t\tdp[i] = int(^uint(0) >> 1)\n\t\tlength := 0\n\t\tfor j := i; j < n; j++ {\n\t\t\tif j > i {\n\t\t\t\tlength++\n\t\t\t}\n\t\t\tlength += len(words[j])\n\t\t\tif length > maxWidth {\n\t\t\t\tbreak\n\t\t\t}\n\t\t\tcost := 0\n\t\t\tif j < n-1 {\n\t\t\t\trem := maxWidth - length\n\t\t\t\tcost = rem*rem + dp[j+1]\n\t\t\t}\n\t\t\tif cost < dp[i] {\n\t\t\t\tdp[i] = cost\n\t\t\t\tnext[i] = j + 1\n\t\t\t}\n\t\t}\n\t}\n\tout := []string{}\n\ti := 0\n\tfor i < n {\n\t\tj := next[i] - 1\n\t\tline := joinWords(words[i : j+1])\n\t\tout = append(out, line)\n\t\ti = next[i]\n\t}\n\treturn out\n}\n\nfunc joinWords(words []string) string {\n\tif len(words) == 0 {\n\t\treturn \"\"\n\t}\n\tout := words[0]\n\tfor i := 1; i < len(words); i++ {\n\t\tout += \" \" + words[i]\n\t}\n\treturn out\n}\n",
