    "code": "package main\ntype TreeNode struct {\n\tVal         int\n\tLeft, Right *TreeNode\n}\n\nfunc findDistanceOfTwoNodes(root, p, q *TreeNode) int {\n\tlca := findLCA(root, p, q)\n\treturn depth(lca, p) + depth(lca, q)\n}\n\nfunc findLCA(root, p, q *TreeNode) *TreeNode {\n\tif root == nil || root == p || root == q {\n\t\treturn root\n\t}\n\tl := findLCA(root.Left, p, q)\n\tr := findLCA(root.Right, p, q)\n\tif l != nil && r != nil {\n\t\treturn root\n\t}\n\tif l != nil {\n\t\treturn l\n\t}\n\treturn r\n}\n\nfunc depth(root, target *TreeNode) int {\n\tif root == nil {\n\t\treturn -1\n\t}\n\tif root == target {\n\t\treturn 0\n\t}\n\td := depth(root.Left, target)\n\tif d >= 0 {\n\t\treturn d + 1\n\t}\n\td = depth(root.Right, target)\n\tif d >= 0 {\n\t\treturn d + 1\n\t}\n\treturn -1\n}\n",
