    "time": "O(n)",
    "space": "O(n)",
    "code": "package main\ntype TreeNode struct {\n\tVal         int\n\tLeft, Right *TreeNode\n}\n\nfunc serializeAndDeserialize(root *TreeNode) (string, *TreeNode) {\n\tif root == nil {\n\t\treturn \"\", nil\n\t}\n\tvar parts []string\n\tq := []*TreeNode{root}\n\tfor len(q) > 0 {\n\t\tnode := q[0]\n\t\tq = q[1:]\n\t\tif node == nil {\n\t\t\tparts = append(parts, \"#\")\n\t\t\tcontinue\n\t\t}\n\t\tparts = append(parts, itoa(node.Val))\n\t\tq = append(q, node.Left, node.Right)\n\t}\n\tdata := joinComma(parts)\n\treturn data, deserializeTree(data)\n}\n\nfunc itoa(n int) string {\n\tif n == 0 {\n\t\treturn \"0\"\n\t}\n\tneg := false\n\tif n < 0 {\n\t\tneg = true\n\t\tn = -n\n\t}\n\tvar d []byte\n\tfor n > 0 {\n\t\td = append(d, byte('0'+n%10))\n\t\tn /= 10\n\t}\n\tif neg {\n\t\td = append(d, '-')\n\t}\n\tfor i, j := 0, len(d)-1; i < j; i, j = i+1, j-1 {\n\t\td[i], d[j] = d[j], d[i]\n\t}\n\treturn string(d)\n}\n\nfunc joinComma(parts []string) string {\n\tif len(parts) == 0 {\n\t\treturn \"\"\n\t}\n\tout := parts[0]\n\tfor i := 1; i < len(parts); i++ {\n\t\tout += \",\" + parts[i]\n\t}\n\treturn out\n}\n\nfunc splitComma(s string) []string {\n\tout := []string{}\n\tstart := 0\n\tfor i := 0; i <= len(s); i++ {\n\t\tif i == len(s) || s[i] == ',' {\n\t\t\tout = append(out, s[start:i])\n\t\t\tstart = i + 1\n\t\t}\n\t}\n\treturn out\n}\n\nfunc atoi(s string) int {\n\tif s == \"#\" || s == \"\" {\n\t\treturn 0\n\t}\n\tneg := false\n\ti := 0\n\tif s[0] == '-' {\n\t\tneg = true\n\t\ti = 1\n\t}\n\tn := 0\n\tfor ; i < len(s); i++ {\n\t\tn = n*10 + int(s[i]-'0')\n\t}\n\tif neg {\n\t\treturn -n\n\t}\n\treturn n\n}\n\nfunc deserializeTree(data string) *TreeNode {\n\tif data == \"\" {\n\t\treturn nil\n\t}\n\tvals := splitComma(data)\n\tidx := 0\n\tvar build func() *TreeNode\n\tbuild = func() *TreeNode {\n\t\tif idx >= len(vals) || vals[idx] == \"#\" {\n\t\t\tidx++\n\t\t\treturn nil\n\t\t}\n\t\tnode := &TreeNode{Val: atoi(vals[idx])}\n\t\tidx++\n\t\tnode.Left = build()\n\t\tnode.Right = build()\n\t\treturn node\n\t}\n\treturn build()\n}\n",
