    "space": "O(n)",
    "code": "package main\nimport \"strings\"\n\n\ntype TreeNode struct {\n\tVal   int\n\tLeft  *TreeNode\n\tRight *TreeNode\n}\n\nfunc getDirections(root *TreeNode, startValue int, destValue int) string {\n\tvar findPath func(node *TreeNode, val int, path *[]byte) bool\n\tfindPath = func(node *TreeNode, val int, path *[]byte) bool {\n\t\tif node == nil {\n\t\t\treturn false\n\t\t}\n\t\tif node.Val == val {\n\t\t\treturn true\n\t\t}\n\t\t*path = append(*path, 'L')\n\t\tif findPath(node.Left, val, path) {\n\t\t\treturn true\n\t\t}\n\t\t(*path)[len(*path)-1] = 'R'\n\t\tif findPath(node.Right, val, path) {\n\t\t\treturn true\n\t\t}\n\t\t*path = (*path)[:len(*path)-1]\n\t\treturn false\n\t}\n\tvar sp, dp []byte\n\tfindPath(root, startValue, &sp)\n\tfindPath(root, destValue, &dp)\n\ti := 0\n\tfor i < len(sp) && i < len(dp) && sp[i] == dp[i] {\n\t\ti++\n\t}\n\tvar sb strings.Builder\n\tfor k := i; k < len(sp); k++ {\n\t\tsb.WriteByte('U')\n\t}\n\tsb.Write(dp[i:])\n\treturn sb.String()\n}\n",
